SELECT count(*) FROM role_type, cast_info, char_name, title, kind_type, movie_keyword, movie_companies WHERE cast_info.role_id = role_type.id AND cast_info.person_role_id = char_name.id AND cast_info.movie_id = title.id AND title.kind_id = kind_type.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id;